const input = $input.first().json || {};

const callback = input.callback_query || null;

// Вариант 1: пришел callback от кнопки search_show_all/search_show_top
if (callback) {
  const data = String(callback.data || '');

  let mode = null;
  let sessionId = null;

  if (data.startsWith('search_show_all:')) {
    mode = 'all';
    sessionId = data.replace('search_show_all:', '').trim();
  }

  if (data.startsWith('search_show_top:')) {
    mode = 'top';
    sessionId = data.replace('search_show_top:', '').trim();
  }

  if (!mode || !sessionId) {
    throw new Error(`Unsupported search results callback: ${data}`);
  }

  return [
    {
      json: {
        user_id: callback.from.id,
        chat_id: callback.message.chat.id,
        callback_query_id: callback.id,
        telegram_message_id: callback.message.message_id,
        search_session_id: sessionId,
        mode,
        is_callback: true
      }
    }
  ];
}

// Вариант 2: прямой вызов из main workflow без кнопки
const searchSessionId =
  input.search_session_id ||
  input.callback_search_session_id ||
  input.session_id ||
  null;

const userId =
  input.user_id ||
  input.message?.from?.id ||
  input.callback_query?.from?.id ||
  null;

const chatId =
  input.chat_id ||
  input.message?.chat?.id ||
  input.callback_query?.message?.chat?.id ||
  userId ||
  null;

const mode = String(input.mode || 'top').trim();

if (!searchSessionId) {
  throw new Error(
    `Missing search_session_id for direct show search results call. Input keys: ${Object.keys(input).join(', ')}`
  );
}

if (!userId || !chatId) {
  throw new Error(
    `Missing user_id/chat_id for direct show search results call. Input keys: ${Object.keys(input).join(', ')}`
  );
}

return [
  {
    json: {
      user_id: userId,
      chat_id: chatId,
      callback_query_id: null,
      telegram_message_id: input.telegram_message_id || null,
      search_session_id: searchSessionId,
      mode,
      is_callback: false
    }
  }
];

